/* ─────────────────────────────────────────────────────────────
   CALC SCORE
───────────────────────────────────────────────────────────── */
function calcScore(trades) {
  if (!trades.length) return 0;
  const wins = trades.filter(t=>t.pnl>0);
  const loses= trades.filter(t=>t.pnl<0);
  const gp   = wins.reduce((s,t)=>s+t.pnl,0);
  const gl   = Math.abs(loses.reduce((s,t)=>s+t.pnl,0))||1;
  const rrs  = trades.filter(t=>t.rr>0).map(t=>t.rr);
  const avgR = rrs.length ? rrs.reduce((a,b)=>a+b,0)/rrs.length : 0;
  const mist = trades.reduce((s,t)=>s+t.mistakes.length,0);
  return Math.round((wins.length/trades.length)*30+(Math.min(gp/gl,3)/3)*30+Math.min(avgR/1.5,1)*20+Math.max(0,20-mist*5));
}

