/* ─────────────────────────────────────────────────────────────
   GAUGE
───────────────────────────────────────────────────────────── */
function Gauge({ score }) {
  const { dark, T } = useThm();
  const arc  = Math.PI * 80;
  const fill = (score/100)*arc;
  const col  = score>=70 ? "#059669" : score>=45 ? "#D97706" : "#DC2626";
  const lbl  = score>=70 ? "Elite"   : score>=45 ? "Developing" : "Needs Work";
  return (
    <div style={{ display:"flex", flexDirection:"column", alignItems:"center", width:"100%" }}>
      <svg viewBox="0 0 200 125" style={{ width:"100%", maxWidth:220, height:"auto" }}>
        <path d="M20 115 A80 80 0 0 1 180 115" fill="none" stroke={T.gridLine} strokeWidth="14" strokeLinecap="round"/>
        <path d="M20 115 A80 80 0 0 1 180 115" fill="none" stroke={col} strokeWidth="14" strokeLinecap="round"
          strokeDasharray={`${fill} ${arc}`} style={{transition:"stroke-dasharray 1.2s ease"}}/>
        <text x="100" y="98"  textAnchor="middle" fontSize="40" fontWeight="900" fill={dark?"#E6EDF3":"#0F172A"}>{score}</text>
        <text x="100" y="116" textAnchor="middle" fontSize="11" fontWeight="700" fill={dark?"#8B949E":"#64748B"} letterSpacing="1.5">{lbl.toUpperCase()}</text>
      </svg>
      <p style={{fontSize:10,color:T.text3,letterSpacing:"0.1em",textTransform:"uppercase",fontWeight:700,marginTop:4}}>Ohm Score</p>
    </div>
  );
}

/* ─────────────────────────────────────────────────────────────
   CARD  —  fully responsive, icon always proportional
───────────────────────────────────────────────────────────── */
function Card({ label, value, sub, color, Icon }) {
  const { dark, T } = useThm();
  const [hov, setHov] = useState(false);
  return (
    <div
      onMouseEnter={()=>setHov(true)}
      onMouseLeave={()=>setHov(false)}
      style={{
        background:T.surface,
        border:`1.5px solid ${hov ? color+"60" : T.border2}`,
        borderRadius:16,
        padding:"18px 20px",
        boxShadow: hov ? `0 8px 24px ${color}22` : "0 1px 4px rgba(0,0,0,0.05)",
        transition:"all 0.2s",
        display:"flex",
        flexDirection:"column",
        gap:14,
        minWidth:0,           /* ← critical: prevents overflow in grid */
      }}
    >
      <div style={{display:"flex",justifyContent:"space-between",alignItems:"flex-start"}}>
        <p style={{
          fontSize:11, fontWeight:700, color:T.text3,
          textTransform:"uppercase", letterSpacing:"0.09em", lineHeight:1.3,
          paddingRight:8, minWidth:0, wordBreak:"break-word"
        }}>{label}</p>
        <InfoTooltip id={label}>
          <div style={{
            width:44, height:44, borderRadius:13, background:color+"18",
            display:"flex", alignItems:"center", justifyContent:"center",
            flexShrink:0,
            transform: hov ? "scale(1.1) rotate(-5deg)" : "scale(1)",
            transition:"transform 0.25s",
            cursor:"pointer"
          }}>
            <Icon size={22} color={color} strokeWidth={2}/>
          </div>
        </InfoTooltip>
      </div>
      <div>
        <p style={{fontSize:28,fontWeight:900,color,lineHeight:1,letterSpacing:"-0.5px",minWidth:0,wordBreak:"break-all"}}>{value}</p>
        {sub && <p style={{fontSize:11,color:T.text3,marginTop:6,fontWeight:500,lineHeight:1.4}}>{sub}</p>}
      </div>
    </div>
  );
}

