function Tip({ active, payload, label }) {
  if (!active || !payload?.length) return null;
  return (
    <div style={{background:"#0F172A",borderRadius:10,padding:"8px 14px",fontSize:12,boxShadow:"0 4px 16px rgba(0,0,0,0.3)"}}>
      <p style={{color:"#94A3B8",marginBottom:4,fontSize:11}}>{label}</p>
      {payload.map((p,i)=>(
        <p key={i} style={{fontWeight:800,color:typeof p.value==="number"&&p.value<0?"#F87171":"#34D399",fontSize:13}}>
          {typeof p.value==="number" ? `$${p.value.toLocaleString()}` : p.value}
        </p>
      ))}
    </div>
  );
}

