function InfoTooltip({ id, children }) {
  const { openInfo } = useInfo();
  const { dark } = useThm();
  const info = INFO_DATA_FULL[id];
  return (
    <span style={{display:"inline-flex",alignItems:"center",gap:4,verticalAlign:"middle"}}>
      {children}
      {info && (
        <span
          onClick={e=>{ e.stopPropagation(); e.preventDefault(); openInfo(id); }}
          style={{
            display:"inline-flex",alignItems:"center",justifyContent:"center",
            width:13,height:13,borderRadius:"50%",flexShrink:0,cursor:"pointer",
            background:dark?"rgba(34,197,94,0.22)":"rgba(34,197,94,0.18)",
            border:"1px solid "+( dark?"rgba(34,197,94,0.5)":"rgba(34,197,94,0.45)" ),
            fontSize:7,fontWeight:900,lineHeight:1,
            color:dark?"#4ADE80":"#16a34a",
            userSelect:"none",
          }}
        >!</span>
      )}
    </span>
  );
}
