        <div style={{marginTop:10,background:T.miniCard,border:`1px solid ${T.border}`,borderRadius:8,padding:"5px 10px",textAlign:"center"}}>
          <p style={{fontSize:11,color:T.text2,fontWeight:700}}>{new Date().toLocaleDateString("en-US",{weekday:"short",month:"short",day:"numeric",year:"numeric"})}</p>
        </div>
