          // stats for subtitle
          const moT   = trades.filter(t=>{const d=new Date(t.date);return d.getFullYear()===calMo.y&&d.getMonth()===calMo.m;});
          const dayT  = selDay ? trades.filter(t=>t.date===selDay) : null;
