          const moWR   = mo.length ? Math.round(moWins/mo.length*100) : 0;
          const moDays = [...new Set(mo.map(t=>t.date))].length;
          const tradingDaysInMonth = (()=>{ let c=0; for(let d=1;d<=calDays;d++){const w=new Date(calMo.y,calMo.m,d).getDay();if(w&&w<6)c++;} return c; })();
          const consistency = tradingDaysInMonth>0 ? Math.round(moDays/tradingDaysInMonth*100) : 0;
          const dailyPnl = Array.from({length:calDays},(_,i)=>{
            const ds=`${calMo.y}-${String(calMo.m+1).padStart(2,"0")}-${String(i+1).padStart(2,"0")}`;
            const dT=trades.filter(t=>t.date===ds);
            return {day:i+1,pnl:dT.reduce((s,t)=>s+t.pnl,0),cnt:dT.length,ds};
          }).filter(d=>d.cnt>0);
          const sortedDays=[...dailyPnl].sort((a,b)=>b.pnl-a.pnl);
          const bestDays=sortedDays.slice(0,3);
          const worstDays=[...sortedDays].reverse().slice(0,3);
