                                fontSize:12,fontWeight:800,color:m.pnl>=0?G:R,
                                background:(m.pnl>=0?G:R)+"15",
                                padding:"2px 9px",borderRadius:10,border:`1px solid ${m.pnl>=0?G:R}25`,
