                a.href=u2;a.download=`ohm-calendar-${MONTHS[calMo.m]}-${calMo.y}.png`;document.body.appendChild(a);a.click();setTimeout(()=>{URL.revokeObjectURL(u2);document.body.removeChild(a);},1000);
